import { prisma } from '../db';

export async function login(entraOid: string) {
  const user = await prisma.user.findFirst({ where: { entraOid: entraOid } });
  return user;
}

import { prisma } from '../db';

export async function report(id: string) {
  return prisma.audit.findMany({ where: { id: id } });
}

import { prisma } from '../db';

export async function get(id: string) {
  return prisma.session.findUnique({ where: { id: id } });
}
